    var sesameClaimsAt       = 0;      // ms timestamp of last scrape
    var sesameYardIdCache    = {};     // { buildingCode -> yardId string }
    var sesameYardIdAt       = {};     // { buildingCode -> ms }
    var SESAME_CACHE_MS      = 20 * 60 * 1000; // 20 min (reduced from 60 to avoid stale JWTs)

