        '#hydra-settings-header{display:flex;align-items:center;justify-content:space-between;padding:12px 16px;background:var(--h-settings-head, #232f3e);border-radius:10px 10px 0 0;border-bottom:1px solid var(--h-border2, #3a4a5c)}',
        '#hydra-settings-title{font-size:15px;font-weight:700;color:#ff9900}',
