    try { document.documentElement.classList.toggle('hydra-light', hydraTheme === 'light'); } catch(e){}

    // ═══════════════════════════════════════════════════════════════════════════
    // SECTION 10: UTILITY FUNCTIONS
    // ═══════════════════════════════════════════════════════════════════════════

    // CPT SLA cutoff in epoch ms: (latest selected CPT window end) - SLA hours.
    // Returns null when SLA is disabled or no CPT windows are selected.
    function computeSlaThresholdMs() {
        if (!cptSlaEnabled) return null;
        if (!selectedCptIds || !selectedCptIds.length) return null;
        var _slaH = (typeof cptSlaHours === 'number' && cptSlaHours > 0) ? cptSlaHours : 4;
        var _lastEnd = null;
        selectedCptIds.forEach(function(id){
            var _d = getCptPresetDates(id);
            var _ems = parseCptMs(_d.end);
            if (_ems !== null && (_lastEnd === null || _ems > _lastEnd)) _lastEnd = _ems;
        });
        if (_lastEnd === null) return null;
        return _lastEnd - _slaH * 3600000;
    }
    function getEffectiveTzOffset() {
        if (tzOverride !== null && !isNaN(tzOverride)) return tzOverride;
        return -new Date().getTimezoneOffset() / 60;
    }

    function fmtDate(d) {
        return ('0' + (d.getMonth() + 1)).slice(-2) + '/' + ('0' + d.getDate()).slice(-2) + '/' + d.getFullYear() + ' ' + ('0' + d.getHours()).slice(-2) + ':' + ('0' + d.getMinutes()).slice(-2);
    }

    function msToLocal(ms) {
        if (!ms) return '—';
        var tzOff = getEffectiveTzOffset();
        var d = new Date(Number(ms) + tzOff * 3600000);
        return ('0' + (d.getUTCMonth() + 1)).slice(-2) + '/' + ('0' + d.getUTCDate()).slice(-2) + ' ' + ('0' + d.getUTCHours()).slice(-2) + ':' + ('0' + d.getUTCMinutes()).slice(-2);
    }
    function parseCptMs(str) {
        if (!str || !str.trim()) return null;
        var tzOff = getEffectiveTzOffset();
        // Format 1: MM/DD/YYYY HH:MM (preset inputs)
        var m = str.trim().match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})\s+(\d{1,2}):(\d{2})$/);
        if (m) {
            var ms = Date.UTC(+m[3], +m[1]-1, +m[2], +m[4], +m[5], 0) - tzOff * 3600000;
            return isNaN(ms) ? null : ms;
        }
        // Format 2: dd-Mon-yy HH:MM (OB dock API)
        var MONTHS = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
        var m2 = str.trim().match(/^(\d{1,2})-(\w{3})-(\d{2})\s+(\d{1,2}):(\d{2})$/);
        if (m2) {
            var mo = MONTHS[m2[2]];
            if (mo === undefined) return null;
            var ms2 = Date.UTC(2000 + +m2[3], mo, +m2[1], +m2[4], +m2[5], 0) - tzOff * 3600000;
            return isNaN(ms2) ? null : ms2;
        }
        return null;
    }

    function cptToMinutes(cptStr) {
        if (!cptStr || cptStr === '\u2014') return null;
        var m = cptStr.trim().match(/(\d{1,2}):(\d{2})\s*$/);
        if (!m) return null;
        return Number(m[1]) * 60 + Number(m[2]);
    }

    function isCptInWindow(cptStr) {
        var startEl = document.getElementById('hydra-cpt-start-input');
        var endEl   = document.getElementById('hydra-cpt-end-input');
        var startVal = startEl ? startEl.value.trim() : '';
        var endVal   = endEl   ? endEl.value.trim()   : '';
        // "— Any —" preset: both inputs cleared → show all rows
        if (!startVal && !endVal) return true;
        // Specific preset: compare against the exact start/end timestamps
        var cptMs   = parseCptMs(cptStr);
        if (cptMs === null) return false;
        var startMs = parseCptMs(startVal);
        var endMs   = parseCptMs(endVal);
        if (startMs !== null && cptMs < startMs) return false;
        if (endMs   !== null && cptMs > endMs)   return false;
        return true;
    }

    function routeMatchesList(route, list) {
        if (!route || !list || !list.length) return false;
        var r = route.toUpperCase();
        return list.some(function(p) { return r.indexOf(p.toUpperCase()) !== -1; });
    }


    function routePill(route, cpt) {
        var c = cptWindowColor(cpt);
        if (!c) return route || '\u2014';
        return '<span style="background:' + c.bg + ';color:' + c.text + ';padding:2px 8px;border-radius:3px;font-weight:600;font-size:11px;border:1px solid var(--h-prog-border, rgba(255,255,255,0.08))">' + (route || '\u2014') + '</span>';
    }

    function cptWindowColor(cptStr) {
        var t = cptToMinutes(cptStr);
        if (t === null) return null;
        for (var i = 0; i < cptWindows.length; i++) {
            var w = cptWindows[i];
            var s = w.startH * 60 + (w.startM || 0);
            var e = w.endH   * 60 + (w.endM   || 0);
            var inWindow = (e <= s) ? (t >= s || t <= e) : (t >= s && t <= e);
            if (inWindow) {
                return { bg: w.bgColor || 'var(--h-bg4, #1a2535)', text: w.textColor || 'var(--h-text, #e8eaf0)' };
            }
        }
        return null;
    }

    function encodeToken(t) { return t.replace(/=/g, '%3D').replace(/\//g, '%2F').replace(/\+/g, '%2B'); }

    // ═══════════════════════════════════════════════════════════════════════════
    // DEBUG INSTRUMENTATION (temporary)
    // ═══════════════════════════════════════════════════════════════════════════
    var _hydraTraceId = 0;
    var _hydraTraceActive = {};
    function hydraTraceStart(label, meta) {
        var id = ++_hydraTraceId;
        var startMs = performance.now();
        _hydraTraceActive[id] = { label: label, startMs: startMs };
        console.log('[Hydra TRACE ' + id + '] START ' + label + (meta ? ' ' + JSON.stringify(meta) : ''));
        _hydraTraceActive[id].stallTimer = setTimeout(function() {
            if (_hydraTraceActive[id]) console.warn('[Hydra TRACE ' + id + '] STALL ' + label + ' still running after 30s');
        }, 30000);
        return id;
    }
    function hydraTraceEnd(id, meta) {
        var entry = _hydraTraceActive[id];
        if (!entry) { console.warn('[Hydra TRACE ' + id + '] END called but no active entry'); return; }
        var dur = (performance.now() - entry.startMs).toFixed(0);
        if (entry.stallTimer) clearTimeout(entry.stallTimer);
        console.log('[Hydra TRACE ' + id + '] END   ' + entry.label + ' (' + dur + 'ms)' + (meta ? ' ' + JSON.stringify(meta) : ''));
        delete _hydraTraceActive[id];
    }
    function hydraTraceFail(id, err) {
        var entry = _hydraTraceActive[id];
        if (!entry) return;
        var dur = (performance.now() - entry.startMs).toFixed(0);
        if (entry.stallTimer) clearTimeout(entry.stallTimer);
        console.error('[Hydra TRACE ' + id + '] FAIL  ' + entry.label + ' (' + dur + 'ms)', err);
        delete _hydraTraceActive[id];
    }
    window.hydraTraceStatus = function() {
        var open = Object.keys(_hydraTraceActive);
        if (!open.length) { console.log('[Hydra TRACE] no active traces'); return; }
        console.log('[Hydra TRACE] ' + open.length + ' active:');
        open.forEach(function(id) {
            var e = _hydraTraceActive[id];
            console.log('  #' + id + ' ' + e.label + ' (' + (performance.now() - e.startMs).toFixed(0) + 'ms elapsed)');
        });
    };

    // Nuke all in-memory auth + in-flight state. Use when refreshes hang.
    function hydraHardReset() {
        console.warn('[Hydra] HARD RESET -- clearing all auth tokens + in-flight state');
        // 1. Clear CSRF token (SSP)
        csrfToken = null;
        tokenFetchedAt = null;
        // 2. Clear YMS JWT
        ymsSecurityToken = null;
        ymsSecurityTokenAt = 0;
        // 3. Reset loading guard so doRefresh can actually run
        isLoading = false;
        // 4. Clear any open trace entries + their stall timers
        Object.keys(_hydraTraceActive).forEach(function(id) {
            var e = _hydraTraceActive[id];
            if (e && e.stallTimer) clearTimeout(e.stallTimer);
        });
        _hydraTraceActive = {};
        // 5. Clear yard state cache so dock panel re-fetches
        if (typeof yardStateData !== 'undefined') yardStateData = null;
        // 5b. Clear Sesame Gate PA caches
        sesameClaims = null; sesameClaimsAt = 0;
        sesameYardIdCache = {}; sesameYardIdAt = {};
        // 6. Reset the refresh button if it's stuck
        var btn = document.getElementById('hydra-refresh-btn');
        if (btn) { btn.disabled = false; btn.textContent = 'Refresh'; }
        // 7. Expose token-age display refresh
        if (typeof updateTokenAgeDisplay === 'function') { try { updateTokenAgeDisplay(); } catch(e) {} }
        console.log('[Hydra] hard reset complete. Fetching fresh YMS token...');
        // 8. Immediately fetch a fresh YMS token (cache-busted)
        fetchYmsSecurityToken(true).then(function(token) {
            if (token) console.log('[Hydra] Hard reset: fresh YMS token acquired (length=' + token.length + ')');
            else console.warn('[Hydra] Hard reset: YMS token fetch failed');
            if (typeof updateIndicators === 'function') updateIndicators();
        });
    }
    window.hydraHardReset = hydraHardReset;

    // ── Sesame Gate Pre-Assignment (PA) helpers ──
    // Fetches user claims (accountId, customerId, login) by scraping the Sesame Gate
    // Console HTML. The server sets an HttpOnly session cookie we can't read, but
    // the browser will auto-attach it to POSTs when withCredentials=true.
    function fetchSesameClaims(forceRefresh) {
        if (!forceRefresh && sesameClaims && (Date.now() - sesameClaimsAt) < SESAME_CACHE_MS) {
            return Promise.resolve(sesameClaims);
        }
        var _tr = hydraTraceStart('fetchSesameClaims');
        var MAX_ATTEMPTS = 10;
        var RETRY_DELAY_MS = 100;

        function attemptScrape(attemptNum) {
            return new Promise(function(resolve) {
                GM_xmlhttpRequest({
                    method: 'GET',
                    url: 'https://trans-logistics.amazon.com/yms/sesameGateConsole/',
                    withCredentials: true,
                    onload: function(r) {
                        try {
                            var html = r.responseText || '';
                            function scrapeField(fieldName, valueCharClass) {
                                var src = '[\'"]"' + fieldName + '":"[\'"]\\s*\\+\\s*"(' + valueCharClass + ')"';
                                var re = new RegExp(src);
                                var m = html.match(re);
                                if (m) return m[1];
                                var src2 = '"' + fieldName + '"\\s*:\\s*"(' + valueCharClass + ')"';
                                var m2 = html.match(new RegExp(src2));
                                return m2 ? m2[1] : null;
                            }
                            var idClass = 'A[A-Z0-9]{13}';
                            var emailClass = '[a-zA-Z0-9._-]+@[a-zA-Z0-9.-]+';
                            var jwtClass = 'eyJ[A-Za-z0-9_-]+\\.eyJ[A-Za-z0-9_-]+\\.[A-Za-z0-9_-]+';
                            var accountId = scrapeField('activeAccountId', idClass) || scrapeField('accountId', idClass);
                            var customerId = scrapeField('customerId', idClass);
                            var login = scrapeField('login', emailClass);
                            var sessionToken = scrapeField('sesameSessionToken', jwtClass);
                            if (accountId && customerId && sessionToken) {
                                resolve({ success: true, data: { accountId: accountId, customerId: customerId, login: login || '', sessionToken: sessionToken } });
                            } else {
                                resolve({ success: false, htmlLen: html.length, accountId: !!accountId, customerId: !!customerId, sessionToken: !!sessionToken });
                            }
                        } catch (e) {
                            resolve({ success: false, error: e.message });
                        }
                    },
                    onerror: function() {
                        resolve({ success: false, error: 'network' });
                    }
                });
            });
        }

        function runWithRetries(attemptNum) {
            return attemptScrape(attemptNum).then(function(result) {
                if (result.success) {
                    sesameClaims = result.data;
                    sesameClaimsAt = Date.now();
                    if (typeof updateIndicators === 'function') updateIndicators();
                    hydraTraceEnd(_tr, { scraped: true, attempts: attemptNum, accountId: result.data.accountId, customerId: result.data.customerId, hasLogin: !!result.data.login, jwtLen: result.data.sessionToken.length });
                    if (attemptNum > 1) console.log('[Hydra] Sesame claims succeeded on attempt ' + attemptNum + '/' + MAX_ATTEMPTS);
                    return sesameClaims;
                }
                // Failed this attempt
                if (attemptNum < MAX_ATTEMPTS) {
                    return new Promise(function(resolve) {
                        setTimeout(function() { resolve(runWithRetries(attemptNum + 1)); }, RETRY_DELAY_MS);
                    });
                }
                // All attempts exhausted
                if (sesameClaims) {
                    hydraTraceEnd(_tr, { scraped: false, usingStaleCache: true, attempts: MAX_ATTEMPTS, cacheAgeMs: Date.now() - sesameClaimsAt });
                    console.warn('[Hydra] Sesame claims scrape failed after ' + MAX_ATTEMPTS + ' attempts; reusing stale cache (age=' + Math.round((Date.now() - sesameClaimsAt) / 1000) + 's)');
                    return sesameClaims;
                }
                hydraTraceFail(_tr, 'claims-not-found-after-' + MAX_ATTEMPTS + '-attempts');
                console.warn('[Hydra] Sesame claims not found after ' + MAX_ATTEMPTS + ' attempts AND no cache available.');
                return null;
            });
        }

        return runWithRetries(1);
    }

    // Fetch yardId for a buildingCode via Sesame findYardIdByBuildingCode.
    // Cached per buildingCode for 15min.
    function fetchSesameYardId(buildingCode, claims, forceRefresh) {
        if (!forceRefresh && sesameYardIdCache[buildingCode] && (Date.now() - (sesameYardIdAt[buildingCode] || 0)) < SESAME_CACHE_MS) {
            return Promise.resolve(sesameYardIdCache[buildingCode]);
        }
        var _tr = hydraTraceStart('fetchSesameYardId ' + buildingCode);
        return new Promise(function(resolve) {
            GM_xmlhttpRequest({
                method: 'POST',
                url: 'https://sesamegateservice-na-ext.amazon.com/findYardIdByBuildingCode',
                headers: {
                    'Content-Type': 'application/json;charset=utf-8',
                    'x-amz-yardtech-sesame-sessionToken': claims.sessionToken || ''
                },
                data: JSON.stringify({
                    buildingCode: buildingCode,
                    context: {
                        requester: 'R4G',
                        login: claims.login || '',
                        accountId: claims.accountId,
                        customerId: claims.customerId
                    }
                }),
                withCredentials: true,
                onload: function(r) {
                    if (r.status === 401 || r.status === 403) {
                        // Session token expired; invalidate claims so next refresh re-scrapes.
                        sesameClaims = null; sesameClaimsAt = 0;
                        hydraTraceFail(_tr, 'HTTP ' + r.status + ' (session expired)');
                        console.warn('[Hydra] Sesame yardId auth failed, claims invalidated');
                        resolve(null);
                        return;
                    }
                    if (r.status < 200 || r.status >= 300) {
                        hydraTraceFail(_tr, 'HTTP ' + r.status);
                        console.warn('[Hydra] Sesame yardId HTTP ' + r.status);
                        resolve(null);
                        return;
                    }
                    try {
                        var data = JSON.parse(r.responseText);
                        var yardId = data.yardId || (data.yard && data.yard.yardId) || null;
                        if (yardId) {
                            sesameYardIdCache[buildingCode] = yardId;
                            sesameYardIdAt[buildingCode] = Date.now();
                        }
                        hydraTraceEnd(_tr, { yardId: !!yardId });
                        resolve(yardId);
                    } catch (e) { hydraTraceFail(_tr, 'parse-err'); resolve(null); }
                },
                onerror: function() { hydraTraceFail(_tr, 'net-err'); resolve(null); }
            });
            setTimeout(function() { hydraTraceFail(_tr, 'timeout-30s'); resolve(null); }, 30000);
        });
    }

    // Main entry: returns a map { vrid -> doorNumber } for INBOUND loads with
    // a pre-assigned dock door at the given buildingCode. Returns {} on any failure
    // (non-fatal — PA display just silently stays off for this refresh).
    function fetchSesamePreAssignments(buildingCode) {
        var _trAll = hydraTraceStart('fetchSesamePreAssignments ' + buildingCode);
        return fetchSesameClaims(false).then(function(claims) {
            if (!claims) { hydraTraceEnd(_trAll, { reason: 'no-claims' }); return {}; }
            return fetchSesameYardId(buildingCode, claims, false).then(function(yardId) {
                if (!yardId) { hydraTraceEnd(_trAll, { reason: 'no-yardId' }); return {}; }
                return new Promise(function(resolve) {
                    var nowSec = Math.floor(Date.now() / 1000);
                    // Window: from 1h ago (catch already-checked-in loads) to 48h ahead
                    var body = {
                        buildingCode: buildingCode,
                        yardId: yardId,
                        startTime: nowSec - 3600,
                        endTime:   nowSec + 172800,
                        context: {
                            requester: 'GEM',
                            login: claims.login || '',
                            accountId: claims.accountId,
                            customerId: claims.customerId
                        }
                    };
                    GM_xmlhttpRequest({
                        method: 'POST',
                        url: 'https://sesamegateservice-na-ext.amazon.com/listLoadsWithInYardDestinationMetadata',
                        headers: {
                            'Content-Type': 'application/json;charset=utf-8',
                            'x-amz-yardtech-sesame-sessionToken': claims.sessionToken || ''
                        },
                        data: JSON.stringify(body),
                        withCredentials: true,
                        onload: function(r) {
                            if (r.status === 401 || r.status === 403) {
                                // Invalidate and return empty; next refresh will re-scrape
                                sesameClaims = null; sesameClaimsAt = 0;
                                sesameYardIdCache = {}; sesameYardIdAt = {};
                                console.warn('[Hydra] Sesame PA auth failed, caches cleared');
                                hydraTraceFail(_trAll, 'HTTP ' + r.status);
                                resolve({});
                                return;
                            }
                            if (r.status < 200 || r.status >= 300) {
                                console.warn('[Hydra] Sesame PA HTTP ' + r.status);
                                hydraTraceFail(_trAll, 'HTTP ' + r.status);
                                resolve({});
                                return;
                            }
                            try {
                                var data = JSON.parse(r.responseText);
                                var items = (data && data.loadsWithInYardDestinationMetadata) || [];
                                var map = {};
                                // Reset meta on each fetch so stale entries don't persist
                                sesameLoadMeta = {};
                                items.forEach(function(item) {
                                    if (!item || !item.load) return;
                                    // Extract VRID from identifiers (type === 'VR_ID')
                                    var ids = item.load.identifiers || [];
                                    var vrid = null;
                                    for (var i = 0; i < ids.length; i++) {
                                        if (ids[i] && ids[i].type === 'VR_ID' && ids[i].identifier) {
                                            vrid = ids[i].identifier; break;
                                        }
                                    }
                                    if (!vrid) return;
                                    // Capture plan.identifier + building for EVERY load -- needed for PA assign popup
                                    var planId = (item.load.plan && item.load.plan.identifier) || null;
                                    var bldg = (item.load.siteCode) || buildingCode;
                                    var currentDoorForMeta = null;
                                    var destForMeta = item.destination;
                                    if (destForMeta && destForMeta.position && destForMeta.position.label) {
                                        var lbl2 = String(destForMeta.position.label);
                                        currentDoorForMeta = lbl2.toUpperCase().indexOf('DD') === 0 ? lbl2.slice(2) : lbl2;
                                    }
                                    sesameLoadMeta[vrid] = { planIdentifier: planId, buildingCode: bldg, currentDoor: currentDoorForMeta };
                                    // Only INBOUND loads contribute to the PA map
                                    if (item.load.designation !== 'INBOUND') return;
                                    if (!destForMeta || !destForMeta.position || !destForMeta.position.label) return;
                                    var lbl = String(destForMeta.position.label);
                                    var doorNum = lbl.toUpperCase().indexOf('DD') === 0 ? lbl.slice(2) : lbl;
                                    map[vrid] = doorNum;
                                });
                                hydraTraceEnd(_trAll, { assignments: Object.keys(map).length, totalLoads: items.length, metaEntries: Object.keys(sesameLoadMeta).length });
                                resolve(map);
                            } catch (e) {
                                hydraTraceFail(_trAll, 'parse-err');
                                resolve({});
                            }
                        },
                        onerror: function() { hydraTraceFail(_trAll, 'net-err'); resolve({}); }
                    });
                    setTimeout(function() { hydraTraceFail(_trAll, 'timeout-45s'); resolve({}); }, 45000);
                });
            });
        });
    }


    // POST a dock door pre-assignment to Sesame Gate. Returns a Promise that
    // resolves to { ok: bool, error: string|null, status: number|null }.
    // Uses the claims + sessionToken already fetched by fetchSesameClaims.
    function assignSesameDoor(vrid, doorNum) {
        var _tr = hydraTraceStart('assignSesameDoor ' + vrid + ' -> DD' + doorNum);
        return fetchSesameClaims(false).then(function(claims) {
            if (!claims) {
                hydraTraceFail(_tr, 'no-claims');
                return { ok: false, error: 'Sesame claims unavailable \u2014 open sesameGateConsole in a tab and refresh.', status: null };
            }
            var meta = sesameLoadMeta[vrid];
            if (!meta || !meta.planIdentifier) {
                // Re-fetch Sesame data and retry
                var _node = (document.getElementById('hydra-node-input').value || 'ORD9').toUpperCase();
                return fetchSesamePreAssignments(_node).then(function() {
                    meta = sesameLoadMeta[vrid];
                    if (!meta || !meta.planIdentifier) {
                        hydraTraceFail(_tr, 'no-plan-id');
                        return { ok: false, error: 'No plan.identifier for ' + vrid + ' even after Sesame reload.' };
                    }
                    // Retry the assignment with fresh data
                    return assignSesameDoorInner(vrid, doorNum, claims, meta, _tr);
                });
            }
            return assignSesameDoorInner(vrid, doorNum, claims, meta, _tr);
            function assignSesameDoorInner(vrid, doorNum, claims, meta, _tr) {
            var buildingCode = meta.buildingCode;
            var doorLabel = 'DD' + String(doorNum).replace(/^DD/i, '');
            var body = {
                buildingCode: buildingCode,
                loadIdentifiers: [{ identifier: vrid, type: 'VR_ID' }],
                plan: { identifier: meta.planIdentifier, isa: null, status: null },
                destination: { identifier: doorLabel, label: doorLabel, positionType: 'PROCESSING' },
                destinationList: [{ identifier: doorLabel, label: doorLabel, positionType: 'PROCESSING' }],
                context: {
                    requester: 'GEM',
                    login: claims.login || '',
                    accountId: claims.accountId,
                    customerId: claims.customerId
                }
            };
            return new Promise(function(resolve) {
                GM_xmlhttpRequest({
                    method: 'POST',
                    url: 'https://sesamegateservice-na-ext.amazon.com/updateInYardDestinationAssignmentForLoad',
                    headers: {
                        'Content-Type': 'application/json;charset=utf-8',
                        'x-amz-yardtech-sesame-sessionToken': claims.sessionToken || ''
                    },
                    data: JSON.stringify(body),
                    withCredentials: true,
                    onload: function(r) {
                        var bodyTxt = r.responseText || '';
                        if (r.status === 401 || r.status === 403) {
                            // Invalidate claims so next attempt re-scrapes the JWT
                            sesameClaims = null; sesameClaimsAt = 0;
                            hydraTraceFail(_tr, 'HTTP ' + r.status + ' (auth)');
                            resolve({ ok: false, error: 'Sesame auth expired \u2014 try again.', status: r.status });
                            return;
                        }
                        if (r.status < 200 || r.status >= 300) {
                            hydraTraceFail(_tr, 'HTTP ' + r.status);
                            var snippet = bodyTxt.slice(0, 200);
                            resolve({ ok: false, error: 'HTTP ' + r.status + ': ' + (snippet || 'no body'), status: r.status });
                            return;
                        }
                        hydraTraceEnd(_tr, { status: r.status, bodyLen: bodyTxt.length });
                        resolve({ ok: true, error: null, status: r.status });
                    },
                    onerror: function(e) {
                        hydraTraceFail(_tr, 'net-err');
                        resolve({ ok: false, error: 'Network error.', status: null });
                    }
                });
                setTimeout(function() {
                    hydraTraceFail(_tr, 'timeout-30s');
                    resolve({ ok: false, error: 'Request timed out after 30s.', status: null });
                }, 30000);
            });
            }
        });
    }

    // POST a dock door pre-assignment REMOVAL to Sesame Gate. Returns a Promise that
    // resolves to { ok: bool, error: string|null, status: number|null }.
    function unassignSesameDoor(vrid) {
        var _tr = hydraTraceStart('unassignSesameDoor ' + vrid);
        return fetchSesameClaims(false).then(function(claims) {
            if (!claims) {
                hydraTraceFail(_tr, 'no-claims');
                return { ok: false, error: 'Sesame claims unavailable \u2014 open sesameGateConsole in a tab and refresh.', status: null };
            }
            var meta = sesameLoadMeta[vrid];
            if (!meta || !meta.planIdentifier) {
                var _node2 = (document.getElementById('hydra-node-input').value || 'ORD9').toUpperCase();
                return fetchSesamePreAssignments(_node2).then(function() {
                    meta = sesameLoadMeta[vrid];
                    if (!meta || !meta.planIdentifier) {
                        hydraTraceFail(_tr, 'no-plan-id');
                        return { ok: false, error: 'No plan.identifier for ' + vrid + ' even after Sesame reload.' };
                    }
                    return doUnassign(claims, meta);
                });
            }
            return doUnassign(claims, meta);
            function doUnassign(claims, meta) {
            var buildingCode = meta.buildingCode;
            var body = {
                buildingCode: buildingCode,
                loadIdentifiers: [{ identifier: vrid, type: 'VR_ID' }],
                plan: { identifier: meta.planIdentifier, isa: null, status: null },
                context: {
                    requester: 'GEM',
                    login: claims.login || '',
                    accountId: claims.accountId,
                    customerId: claims.customerId
                }
            };
            return new Promise(function(resolve) {
                GM_xmlhttpRequest({
                    method: 'POST',
                    url: 'https://sesamegateservice-na-ext.amazon.com/removeInYardDestinationAssignmentForLoad',
                    headers: {
                        'Content-Type': 'application/json;charset=utf-8',
                        'x-amz-yardtech-sesame-sessionToken': claims.sessionToken || ''
                    },
                    data: JSON.stringify(body),
                    withCredentials: true,
                    onload: function(r) {
                        var bodyTxt = r.responseText || '';
                        if (r.status === 401 || r.status === 403) {
                            sesameClaims = null; sesameClaimsAt = 0;
                            hydraTraceFail(_tr, 'HTTP ' + r.status + ' (auth)');
                            resolve({ ok: false, error: 'Sesame auth expired \u2014 try again.', status: r.status });
                            return;
                        }
                        if (r.status < 200 || r.status >= 300) {
                            hydraTraceFail(_tr, 'HTTP ' + r.status);
                            var snippet = bodyTxt.slice(0, 200);
                            resolve({ ok: false, error: 'HTTP ' + r.status + ': ' + (snippet || 'no body'), status: r.status });
                            return;
                        }
                        // DIAG: Sesame often returns 200 with an error/no-op body.
                        console.log('[Hydra UNASSIGN DIAG] status=' + r.status + ' reqBody=' + JSON.stringify(body));
                        console.log('[Hydra UNASSIGN DIAG] respBody=' + bodyTxt);
                        var _lc = bodyTxt.toLowerCase();
                        if (_lc.indexOf('error') !== -1 || _lc.indexOf('exception') !== -1 || _lc.indexOf('fail') !== -1) {
                            hydraTraceFail(_tr, 'body-error');
                            resolve({ ok: false, error: 'Sesame returned 200 but body indicates failure: ' + bodyTxt.slice(0, 200), status: r.status });
                            return;
                        }
                        hydraTraceEnd(_tr, { status: r.status, bodyLen: bodyTxt.length });
                        resolve({ ok: true, error: null, status: r.status });
                    },
                    onerror: function(e) {
                        hydraTraceFail(_tr, 'net-err');
                        resolve({ ok: false, error: 'Network error.', status: null });
                    }
                });
                setTimeout(function() {
                    hydraTraceFail(_tr, 'timeout-30s');
                    resolve({ ok: false, error: 'Request timed out after 30s.', status: null });
                }, 30000);
            });
            }
        });
    }

    // Safe escaper for data attribute values
    function encodeHtmlAttr(s) {
        return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    }

    // Build the PA assignment modal once, reuse on every click.
    function ensurePaAssignModal() {
        var ex = document.getElementById('hydra-pa-overlay');
        if (ex) return ex;
        var ov = document.createElement('div');
        ov.id = 'hydra-pa-overlay';
        ov.innerHTML =
            '<div id="hydra-pa-modal">' +
                '<h3 id="hydra-pa-title">Pre-assign Door</h3>' +
                '<div class="hydra-pa-sub" id="hydra-pa-current">Current: \u2014</div>' +
                '<div class="hydra-pa-row">' +
                    '<label for="hydra-pa-input">Door number</label>' +
                    '<input type="text" id="hydra-pa-input" maxlength="6" inputmode="numeric" placeholder="e.g. 221">' +
                '</div>' +
                '<div class="hydra-pa-status" id="hydra-pa-status"></div>' +
                '<div class="hydra-pa-btns">' +
                    '<button class="hydra-pa-cancel" id="hydra-pa-cancel-btn">Cancel</button>' +
                    '<button class="hydra-pa-cancel" id="hydra-pa-unassign-btn" style="background:var(--h-danger-bg, #3a1a1a);color:#ef5350;border:1px solid var(--h-danger-border, #5a2a2a);display:none">Unassign</button>' +
                    '<button class="hydra-pa-confirm" id="hydra-pa-confirm-btn">Confirm</button>' +
                '</div>' +
            '</div>';
        document.body.appendChild(ov);
        // Close on overlay click (but not modal-body click)
        ov.addEventListener('click', function(e) {
            if (e.target === ov) closePaAssignPopup();
        });
        document.getElementById('hydra-pa-cancel-btn').addEventListener('click', closePaAssignPopup);
        // Enter key triggers confirm
        document.getElementById('hydra-pa-input').addEventListener('keydown', function(e) {
            if (e.key === 'Enter') document.getElementById('hydra-pa-confirm-btn').click();
            else if (e.key === 'Escape') closePaAssignPopup();
        });
        // Only allow digits in the input
        document.getElementById('hydra-pa-input').addEventListener('input', function(e) {
            this.value = this.value.replace(/[^0-9]/g, '');
        });
        return ov;
    }

    function closePaAssignPopup() {
        var ov = document.getElementById('hydra-pa-overlay');
        if (ov) ov.classList.remove('open');
    }

    function openPaAssignPopup(vrid, currentDoor) {
        var ov = ensurePaAssignModal();
        document.getElementById('hydra-pa-title').textContent = 'Pre-assign Door \u2014 ' + vrid;
        var curEl = document.getElementById('hydra-pa-current');
        curEl.textContent = currentDoor ? ('Currently pre-assigned to: ' + currentDoor) : 'No current pre-assignment';
        var input = document.getElementById('hydra-pa-input');
        input.value = currentDoor || '';
        var statusEl = document.getElementById('hydra-pa-status');
        statusEl.textContent = '';
        statusEl.className = 'hydra-pa-status';
        var confirmBtn = document.getElementById('hydra-pa-confirm-btn');
        confirmBtn.disabled = false;
        confirmBtn.textContent = 'Confirm';
        // Rewire confirm button with closure over vrid
        confirmBtn.onclick = function() {
            var doorNum = (input.value || '').trim();
            if (!/^\d+$/.test(doorNum)) {
                statusEl.textContent = 'Please enter a numeric door number.';
                statusEl.className = 'hydra-pa-status err';
                return;
            }
            confirmBtn.disabled = true;
            confirmBtn.textContent = 'Sending...';
            statusEl.textContent = '';
            statusEl.className = 'hydra-pa-status';
            assignSesameDoor(vrid, doorNum).then(function(res) {
                if (res.ok) {
                    statusEl.textContent = '\u2714 Assigned ' + vrid + ' to door ' + doorNum;
                    statusEl.className = 'hydra-pa-status ok';
                    // Update the row's door cell in-place without full refresh
                    for (var _i = 0; _i < ibTableData.length; _i++) {
                        if (ibTableData[_i].vrid === vrid) {
                            ibTableData[_i].location = doorNum;
                            ibTableData[_i].isPA = true;
                            ibTableData[_i].paDoorNum = doorNum;
                            break;
                        }
                    }
                    // Update sesamePaDoorInfo for dock panel
                    sesamePaDoorInfo[String(doorNum)] = { vrid: vrid, route: '' };
                    setTimeout(function() {
                        closePaAssignPopup();
                        renderIBTable();
                        if (typeof puActive !== 'undefined' && puActive) renderAllPanes();
                        renderDockDoorPanel(); updateIndicators();
                    }, 800);
                } else {
                    statusEl.textContent = '\u2717 ' + (res.error || 'Failed');
                    statusEl.className = 'hydra-pa-status err';
                    confirmBtn.disabled = false;
                    confirmBtn.textContent = 'Retry';
                }
            });
        };
        // Show/hide Unassign button based on whether there's a current PA
        var unassignBtn = document.getElementById('hydra-pa-unassign-btn');
        if (unassignBtn) {
            unassignBtn.style.display = currentDoor ? '' : 'none';
            unassignBtn.disabled = false;
            unassignBtn.textContent = 'Unassign';
            unassignBtn.onclick = function() {
                unassignBtn.disabled = true;
                unassignBtn.textContent = 'Removing...';
                statusEl.textContent = '';
                statusEl.className = 'hydra-pa-status';
                unassignSesameDoor(vrid).then(function(res) {
                    if (res.ok) {
                        statusEl.textContent = '\u2714 Pre-assignment removed for ' + vrid;
                        statusEl.className = 'hydra-pa-status ok';
                        // Update the row in-place
                        for (var _i = 0; _i < ibTableData.length; _i++) {
                            if (ibTableData[_i].vrid === vrid) {
                                ibTableData[_i].location = '\u2014';
                                ibTableData[_i].isPA = false;
                                ibTableData[_i].paDoorNum = null;
                                break;
                            }
                        }
                        // Remove from sesamePaDoorInfo
                        if (currentDoor) delete sesamePaDoorInfo[String(currentDoor)];
                        setTimeout(function() {
                            closePaAssignPopup();
                            renderIBTable();
                            if (typeof puActive !== 'undefined' && puActive) renderAllPanes();
                            renderDockDoorPanel();
                        }, 800);
                    } else {
                        statusEl.textContent = '\u2717 ' + (res.error || 'Failed');
                        statusEl.className = 'hydra-pa-status err';
                        unassignBtn.disabled = false;
                        unassignBtn.textContent = 'Retry';
                    }
                });
            };
        }

        ov.classList.add('open');
        setTimeout(function() { input.focus(); input.select(); }, 50);
    }
    // Format milliseconds-until-ETA as a compact countdown string.
    // Examples: '2h 15m', '45m', '-30m', '-2h 15m'. Returns em-dash if ms is falsy.
    function formatEtaCountdown(etaMs) {
        if (!etaMs || typeof etaMs !== 'number') return '—';
        var diffMin = Math.round((etaMs - Date.now()) / 60000);
        var past = diffMin < 0;
        var abs = Math.abs(diffMin);
        var sign = past ? '-' : '';
        var countdown = (abs < 60) ? (sign + abs + 'm') : (sign + Math.floor(abs / 60) + 'h ' + (abs % 60) + 'm');
        // Append arrival time in local TZ e.g. "(08:45)"
        var tzOff = getEffectiveTzOffset();
        var arrD = new Date(etaMs + tzOff * 3600000);
        var arrTime = '(' + ('0' + arrD.getUTCHours()).slice(-2) + ':' + ('0' + arrD.getUTCMinutes()).slice(-2) + ')';
        return countdown + ' ' + arrTime;
    }

    function equipCell(t) {
        if (!t) return { html: '?', label: 'Unknown' };
        var k = t.toUpperCase().trim(), i = EQUIP_MAP[k];
        if (!i) return { html: '?', label: t };
        if (i.isSvg) return { html: '<img src="' + i.src + '" style="width:' + i.w + 'px;height:' + i.h + 'px;vertical-align:middle;">', label: i.label };
        return { html: i.src, label: i.label };
    }


    function routeColorClass(r) {
        var isCtn = r.fluid < 50 && r.containerized > 50;
        if (isCtn) return r.noncon > 50 ? 'route-yellow' : 'route-green';
        if (r.total > 0) return r.noncon > 50 ? 'route-orange' : 'route-blue';
        return '';
    }

    function cptCellHtml(v, noHeat) {
        if (noHeat) return '<td style="padding:3px 10px">' + v + '</td>';
        var bg, color = '#fff', fw = ';font-weight:700', extra = '';
        if (v >= 200) { bg = '#b71c1c'; extra = ';box-shadow:inset 0 0 8px rgba(0,0,0,.4)'; }
        else if (v >= 100) { bg = '#c62828'; }
        else if (v >= 40) { bg = '#e65100'; }
        else if (v >= 10) { bg = '#f57f17'; color = '#111'; }
        else { bg = '#1b5e20'; fw = ''; }
        return '<td style="background:' + bg + ';color:' + color + fw + extra + ';border-radius:3px;padding:3px 10px">' + v + '</td>';
    }

    function ncCptCellHtml(v, noHeat) {
        v = v || 0;
        if (noHeat) return '<td style="padding:3px 10px">' + v + '</td>';
        var bg, color = '#fff', fw = ';font-weight:700', extra = '';
        if      (v >= 200) { bg = '#b71c1c'; extra = ';box-shadow:inset 0 0 8px rgba(0,0,0,.4)'; }
        else if (v >= 100) { bg = '#c62828'; }
        else if (v >= 40)  { bg = '#e65100'; }
        else if (v >= 10)  { bg = '#f57f17'; color = '#111'; }
        else               { bg = '#1b5e20'; fw = ''; }
        return '<td style="background:' + bg + ';color:' + color + fw + extra + ';border-radius:3px;padding:3px 10px">' + v + '</td>';
    }


    // Return an inline-style string for the Containerized % cell based on
    // packages-per-container (containerized / containers). Returns '' if
    // the ratio is undefined (no containers), so the cell stays neutral.
    // Applies both color (text) and background (subtle alpha).
    function ppcColorStyle(containerized, containers) {
        var c = Number(containers) || 0;
        if (c <= 0) return '';
        var ppc = (Number(containerized) || 0) / c;
        var _ppcLight = document.documentElement.classList.contains('hydra-light');
        var color, fw = 'font-weight:700';
        if (ppc < 50) { color = _ppcLight ? '#d32f2f' : '#ef5350'; }
        else if (ppc < 60) { color = _ppcLight ? '#e64a19' : '#ff7043'; }
        else if (ppc < 70) { color = _ppcLight ? '#ef6c00' : '#ffa726'; }
        else if (ppc < 80) { color = _ppcLight ? '#f9a825' : '#ffee58'; }
        else { color = _ppcLight ? '#2e7d32' : '#66bb6a'; }
        return 'color:' + color + ';' + fw;
    }

    function progressBarHtml(total, remaining) {
        var pct = (total > 0) ? Math.max(0, Math.min(100, Math.round(((total - remaining) / total) * 100))) : 0;
        var cls = pct < 10 ? 'prog-0' : pct < 25 ? 'prog-1' : pct < 50 ? 'prog-2' : pct < 75 ? 'prog-3' : 'prog-4';
        return '<td class="col-progress"><div class="prog-wrap"><div class="prog-bar ' + cls + '" style="width:' + pct + '%"></div><span class="prog-label">' + pct + '%</span></div></td>';
    }

    function progressBarHtmlOB(planned, loaded) {
        var pct = (planned > 0) ? Math.max(0, Math.min(100, Math.round((loaded / planned) * 100))) : 0;
        var cls = pct < 10 ? 'prog-0' : pct < 25 ? 'prog-1' : pct < 50 ? 'prog-2' : pct < 75 ? 'prog-3' : 'prog-4';
        return '<td class="col-progress"><div class="prog-wrap"><div class="prog-bar ' + cls + '" style="width:' + pct + '%"></div><span class="prog-label">' + pct + '%</span></div></td>';
    }

    // ═══════════════════════════════════════════════════════════════════════════
    // SECTION 11: CPT FUNCTIONS
    // ═══════════════════════════════════════════════════════════════════════════

    function saveCptWindows() { try { localStorage.setItem(STORAGE_KEYS.cptWindows, JSON.stringify(cptWindows)); } catch (e) {} }
    function loadCptWindows() {
        try {
            var raw = localStorage.getItem(STORAGE_KEYS.cptWindows);
            if (raw) { var arr = JSON.parse(raw); if (Array.isArray(arr) && arr.length > 0) cptWindows = arr; }
        } catch (e) {}
    }

    function getActiveCptPreset(h) {
        for (var i = 0; i < cptWindows.length; i++) {
            var w = cptWindows[i];
            if (w.endH < w.startH) { if (h >= w.startH || h < w.endH) return w.id; }
            else { if (h >= w.startH && h < w.endH) return w.id; }
        }
        return cptWindows.length > 0 ? cptWindows[0].id : null;
    }

    function getCptPresetDates(id) {
        var win = cptWindows.find(function(w) { return w.id === id; });
        if (!win) return { start: '', end: '' };

        // Work in effective TZ — convert "now" to a UTC-epoch that represents
        // the current wall-clock time in the override TZ
        var tzOff = getEffectiveTzOffset();
        var nowUtc = Date.now();
        // "Local midnight" in effective TZ
        var nowInTz = new Date(nowUtc + tzOff * 3600000); // UTC date whose Y/M/D matches effective TZ
        var yyyyTz = nowInTz.getUTCFullYear();
        var mmTz   = nowInTz.getUTCMonth();
        var ddTz   = nowInTz.getUTCDate();
        var hTz    = nowInTz.getUTCHours();
        var minTz  = nowInTz.getUTCMinutes();

        // Build start/end as UTC ms representing that wall-clock time in effective TZ
        var startMs = Date.UTC(yyyyTz, mmTz, ddTz, win.startH, win.startM || 0, 0) - tzOff * 3600000;
        var endMs   = Date.UTC(yyyyTz, mmTz, ddTz, win.endH,   win.endM   || 0, 0) - tzOff * 3600000;

        // +1d flag adjustment (user-controlled)
        if (win.startPlusDay) startMs += 86400000;
        if (win.endPlusDay)   endMs   += 86400000;

        // Overnight window auto-adjustment (only if no manual +1d flags set)
        if (!win.startPlusDay && !win.endPlusDay) {
            var isOvernight = win.endH < win.startH || (win.endH === win.startH && (win.endM || 0) < (win.startM || 0));
            if (isOvernight) {
                var pastEnd = (hTz < win.endH) || (hTz === win.endH && minTz < (win.endM || 0));
                if (pastEnd) startMs -= 86400000;   // start was yesterday
                else         endMs   += 86400000;   // end is tomorrow
            }
        }

        // Format back as display string (interpret as effective TZ)
        function toDisplayStr(ms) {
            var d = new Date(ms + tzOff * 3600000);
            return ('0'+(d.getUTCMonth()+1)).slice(-2)+'/'+('0'+d.getUTCDate()).slice(-2)+'/'+d.getUTCFullYear()+' '+('0'+d.getUTCHours()).slice(-2)+':'+('0'+d.getUTCMinutes()).slice(-2);
        }
        return { start: toDisplayStr(startMs), end: toDisplayStr(endMs) };
    }

    function applyCptPreset(id) {
        var startEl = document.getElementById('hydra-cpt-start-input');
        var endEl   = document.getElementById('hydra-cpt-end-input');
        if (id === 'any') {
            if (startEl) startEl.value = '';
            if (endEl)   endEl.value   = '';
            return;
        }
        var d = getCptPresetDates(id);
        if (startEl) startEl.value = d.start;
        if (endEl)   endEl.value   = d.end;
        saveAllSettings();
        reseedDynSelHardcoded();
        if (activeView === 'OB') { renderOBTabs(); renderOBTable(); }
        else if (activeView === 'PS') { renderPSTable(); }
        else { renderIBTabs(); renderIBTable(); }
    }

    function buildCptOptions() {
        var activePresetId = getActiveCptPreset(new Date().getHours());
        var anySelected = '';   // 'any' is never the auto-active default
        var opts = '<option value="any"' + anySelected + '>— Any —</option>';
        opts += cptWindows.map(function(w) {
            var timeStr = ('0' + w.startH).slice(-2) + ':' + ('0' + (w.startM || 0)).slice(-2) +
                          '-' + ('0' + w.endH).slice(-2) + ':' + ('0' + (w.endM || 0)).slice(-2);
            var selected = w.id === activePresetId ? ' selected' : '';
            return '<option value="' + w.id + '"' + selected + '>' + w.label + '  ' + timeStr + '</option>';
        }).join('');
        return opts;
    }

    // OB ROUTE SETTINGS FUNCTIONS (ported from OLT 7.4)
    // ═══════════════════════════════════════════════════════════════════════════

    function obIsRouteEnabled(grpKey, rt) {
        var key = grpKey + '|' + rt;
        return obRouteItemEnabled.hasOwnProperty(key) ? obRouteItemEnabled[key] : true;
    }

    // Find which OB_ROUTE_GROUPS group a vrid's route belongs to (substring match).
    function findRouteGroupForRoute(route) {
        if (!route) return null;
        var R = route.toUpperCase();
        var found = null;
        Object.keys(OB_ROUTE_GROUPS).forEach(function(grp) {
            OB_ROUTE_GROUPS[grp].routes.forEach(function(pat) {
                if (!found && R.indexOf(pat.toUpperCase()) !== -1) found = { grp: grp, pat: pat };
            });
        });
        return found;
    }
    // ----- Dynamic selection (dynSel) helpers -----
    // dynSel maps route -> { cptStr: true }. Session-scoped working set used by chase tabs.
    function dynSelHas(route, cpt) {
        return !!(dynSel[route] && cpt && dynSel[route][cpt]);
    }
    function dynSelRouteHas(route) {
        return !!(dynSel[route] && Object.keys(dynSel[route]).length);
    }
    function dynSelToggle(route, cpt) {
        if (!route || !cpt) return;
        if (!dynSel[route]) dynSel[route] = {};
        if (dynSel[route][cpt]) {
            delete dynSel[route][cpt];
            if (!Object.keys(dynSel[route]).length) delete dynSel[route];
        } else {
            dynSel[route][cpt] = true;
        }
    }
    function dynSelRemoveRoute(route) {
        if (dynSel[route]) delete dynSel[route];
    }
    function dynSelCpts(route) {
        return dynSel[route] ? Object.keys(dynSel[route]) : [];
    }
    function dynSelRoutes() {
        return Object.keys(dynSel).filter(function(r){ return Object.keys(dynSel[r]||{}).length; });
    }
    // True if (route,cpt) is in the dynamic selection. If dynSel is empty
    // (not curated yet this session), fall back to legacy settings+window filter.
    function dynSelMatches(route, cpt) {
        var hasDyn = false;
        for (var k in dynSel) { if (Object.keys(dynSel[k]||{}).length) { hasDyn = true; break; } }
        if (hasDyn) return dynSelHas(route, cpt);
        var selRoutes = getSelectedObRoutes();
        if (selRoutes.length > 0 && !routeMatchesList(route, selRoutes)) return false;
        return isCptInWindow(cpt);
    }
    // True if `route` is in the dynamic selection (any CPT). DDU prefix aware.
    // Fallback to legacy settings routes when dynSel is empty.
    function dynSelRouteMatches(route) {
        var hasDyn = false;
        for (var k in dynSel) { if (Object.keys(dynSel[k]||{}).length) { hasDyn = true; break; } }
        var R = (route || '').toUpperCase();
        if (hasDyn) {
            var routes = dynSelRoutes();
            var m = routes.some(function(sr){ return R.indexOf(sr.toUpperCase()) !== -1 || sr.toUpperCase().indexOf(R) !== -1; });
            if (!m && R.indexOf('DDU-') === 0) m = routes.some(function(sr){ return sr.toUpperCase().indexOf('DDU-') === 0; });
            return m;
        }
        var selRoutes = getSelectedObRoutes();
        if (selRoutes.length === 0) return true;
        var matched = routeMatchesList(route, selRoutes);
        if (!matched && R.indexOf('DDU-') === 0) matched = selRoutes.some(function(sr){ return sr.indexOf('DDU-') === 0; });
        return matched;
    }
    function dynSelIsHardcoded(route, cpt) {
        if (!dynSelHardcoded[route]) return false;
        if (cpt === undefined) return Object.keys(dynSelHardcoded[route]).length > 0;
        return !!dynSelHardcoded[route][cpt];
    }
    // Compute the current hardcoded (route,cpt) set from persistent settings + global window.
    // Returns { route: { cpt: true } } for all loaded VRIDs whose route is persistently
    // selected and whose CPT fits the global window.
    function computeHardcodedSet() {
        var hc = {};
        var selRoutes = getSelectedObRoutes();
        var rows = Array.isArray(obTableData.obvrids) ? obTableData.obvrids : [];
        rows.forEach(function(r) {
            if (!r.route || !r.cpt) return;
            if (selRoutes.length && !routeMatchesList(r.route, selRoutes)) return;
            if (!isCptInWindow(r.cpt)) return;
            if (!hc[r.route]) hc[r.route] = {};
            hc[r.route][r.cpt] = true;
        });
        return hc;
    }

    // Seed dynSel once per session from persistent settings + current global CPT window.
    function seedDynSel() {
        if (dynSelSeeded) return;
        // Don't lock the seed until real data exists. If obvrids is empty (e.g. a
        // render fired before/while data loaded), skip -- we'll seed on the next
        // render once rows are present. Otherwise the seed locks itself empty.
        if (!Array.isArray(obTableData.obvrids) || !obTableData.obvrids.length) return;
        dynSelSeeded = true;
        dynSel = {};
        dynSelHardcoded = computeHardcodedSet();
        // dynSel starts as a clone of the hardcoded set
        Object.keys(dynSelHardcoded).forEach(function(rt) {
            dynSel[rt] = {};
            Object.keys(dynSelHardcoded[rt]).forEach(function(cpt) { dynSel[rt][cpt] = true; });
        });
    }

    // Reconcile hardcoded layer after a global settings change (CPT window / routes).
    // Removes hardcoded entries that no longer qualify; adds new ones. Dynamic entries
    // (present in dynSel but NOT in the old hardcoded set) are preserved untouched.
    function reseedDynSelHardcoded() {
        if (!dynSelSeeded) return;  // nothing to reconcile until first seed
        var oldHard = dynSelHardcoded || {};
        var newHard = computeHardcodedSet();
        // Remove old hardcoded (route,cpt) that are NOT dynamic and NOT in newHard
        Object.keys(oldHard).forEach(function(rt) {
            Object.keys(oldHard[rt]).forEach(function(cpt) {
                var stillHard = newHard[rt] && newHard[rt][cpt];
                if (!stillHard) {
                    // Only remove if it was purely hardcoded (i.e., still flagged hardcoded).
                    // If user also dynamically selected it, removing the hardcoded flag but
                    // keeping the selection is desired only when it was dynamic-added.
                    // Heuristic: a purely-hardcoded entry gets removed; we cannot distinguish
                    // a user re-add, so treat oldHard entries as removable.
                    if (dynSel[rt]) { delete dynSel[rt][cpt]; if (!Object.keys(dynSel[rt]).length) delete dynSel[rt]; }
                }
            });
        });
        // Add new hardcoded (route,cpt)
        Object.keys(newHard).forEach(function(rt) {
            Object.keys(newHard[rt]).forEach(function(cpt) {
                if (!dynSel[rt]) dynSel[rt] = {};
                dynSel[rt][cpt] = true;
            });
        });
        dynSelHardcoded = newHard;
    }


    function getSelectedObRoutes() {
        var result = [];
        Object.keys(OB_ROUTE_GROUPS).forEach(function(grp) {
            if (!obRouteGroupEnabled[grp]) return;
            OB_ROUTE_GROUPS[grp].routes.forEach(function(rt) {
                if (obIsRouteEnabled(grp, rt)) result.push(rt);
            });
        });
        return result;
    }

    function buildObRouteItemHtml(grpKey, rt, idx) {
        var grpOn = obRouteGroupEnabled[grpKey];
        var rtOn  = obIsRouteEnabled(grpKey, rt);
        var chk   = rtOn  ? ' checked' : '';
        var dis   = grpOn ? '' : ' disabled';
        var disCls = grpOn ? '' : ' disabled';
        return '<div class="hydra-ob-route-item" data-grp="' + grpKey + '" data-idx="' + idx + '">' +
               '<input type="checkbox" id="hydra-ob-ri-' + grpKey + '-' + idx + '"' + chk + dis + '>' +
               '<label for="hydra-ob-ri-' + grpKey + '-' + idx + '" class="' + disCls + '">' + rt + '</label>' +
               '<button class="hydra-ob-route-item-del" data-grp="' + grpKey + '" data-idx="' + idx + '" title="Remove">&#x2715;</button>' +
               '</div>';
    }

    function renderObRouteGroups() {
        var container = document.getElementById('hydra-ob-route-groups');
        if (!container) return;
        var html = '';
        Object.keys(OB_ROUTE_GROUPS).forEach(function(grpKey) {
            var grp = OB_ROUTE_GROUPS[grpKey];
            var checked = obRouteGroupEnabled[grpKey] ? ' checked' : '';
            html += '<div class="hydra-ob-route-group" id="hydra-ob-grp-' + grpKey + '">' +
                    '<div class="hydra-ob-route-group-header">' +
                    '<input type="checkbox" id="hydra-ob-rg-' + grpKey + '"' + checked + '>' +
                    '<input type="text" class="hydra-ob-group-name-input" data-grp="' + grpKey + '" value="' + grp.label + '" title="Click to rename">' +
                    '<button class="hydra-ob-group-clear-btn" data-grp="' + grpKey + '" title="Remove ALL routes in this group" style="background:none;border:none;color:#a05050;font-size:15px;font-weight:700;cursor:pointer;padding:0 4px;line-height:1">&#10005;</button>' +
                    '</div>' +
                    '<div id="hydra-ob-rl-' + grpKey + '">';
            grp.routes.forEach(function(rt, idx) { html += buildObRouteItemHtml(grpKey, rt, idx); });
            html += '</div>' +
                    '<div class="hydra-ob-route-add-row">' +
                    '<input type="text" class="hydra-ob-route-add-input" id="hydra-ob-ra-' + grpKey + '" placeholder="Add route...">' +
                    '<button class="hydra-ob-route-add-btn" data-grp="' + grpKey + '">+</button>' +
                    '</div></div>';
        });
        container.innerHTML = html;
        bindObRouteEvents();
        // Collapse handled by delegated listener in setupEvents
    }

    function bindObRouteEvents() {
        // Group name inputs (editable)
        document.querySelectorAll('.hydra-ob-group-name-input').forEach(function(inp) {
            inp.addEventListener('input', function() {
                var grpKey = inp.dataset.grp;
                if (OB_ROUTE_GROUPS[grpKey]) {
                    OB_ROUTE_GROUPS[grpKey].label = inp.value;
                    saveAllSettings();
                }
            });
            inp.addEventListener('click', function(e) { e.stopPropagation(); });
        });
        // Group checkboxes
        Object.keys(OB_ROUTE_GROUPS).forEach(function(grpKey) {
            var cb = document.getElementById('hydra-ob-rg-' + grpKey);
            if (!cb) return;
            cb.addEventListener('change', function() {
                obRouteGroupEnabled[grpKey] = cb.checked;
                if (cb.checked) {
                    OB_ROUTE_GROUPS[grpKey].routes.forEach(function(rt) {
                        obRouteItemEnabled[grpKey + '|' + rt] = true;
                    });
                }
                refreshObRouteItemStates(grpKey);
                saveAllSettings();
                reseedDynSelHardcoded();
                if (activeView === 'OB' && obActiveTab === 'obvrids') { renderOBTabs(); renderOBVridsTable(); }
            });
        });
        // Item checkboxes
        document.querySelectorAll('.hydra-ob-route-item input[type="checkbox"]').forEach(function(cb) {
            cb.addEventListener('change', function() {
                var item = cb.closest('.hydra-ob-route-item');
                if (!item) return;
                var grpKey = item.dataset.grp;
                var idx    = Number(item.dataset.idx);
                var rt     = OB_ROUTE_GROUPS[grpKey].routes[idx];
                if (!rt) return;
                obRouteItemEnabled[grpKey + '|' + rt] = cb.checked;
                updateObGroupCheckbox(grpKey);
                saveAllSettings();
                reseedDynSelHardcoded();
                if (activeView === 'OB' && obActiveTab === 'obvrids') { renderOBTabs(); renderOBVridsTable(); }
            });
        });
        // Delete buttons
        document.querySelectorAll('.hydra-ob-route-item-del').forEach(function(btn) {
            btn.addEventListener('click', function(e) {
                e.stopPropagation();
                var grpKey = btn.dataset.grp, idx = Number(btn.dataset.idx);
                var removed = OB_ROUTE_GROUPS[grpKey].routes.splice(idx, 1)[0];
                if (removed) delete obRouteItemEnabled[grpKey + '|' + removed];
                rebuildObRouteList(grpKey);
                saveAllSettings();
            });
        });
        // Clear-all buttons (remove every route in the group)
        document.querySelectorAll('.hydra-ob-group-clear-btn').forEach(function(btn) {
            btn.addEventListener('click', function(e) {
                e.stopPropagation();
                var grpKey = btn.dataset.grp;
                var grp = OB_ROUTE_GROUPS[grpKey];
                if (!grp || !grp.routes.length) return;
                if (!confirm('Remove all ' + grp.routes.length + ' routes from "' + grp.label + '"?')) return;
                grp.routes.forEach(function(rt) { delete obRouteItemEnabled[grpKey + '|' + rt]; });
                grp.routes = [];
                rebuildObRouteList(grpKey);
                updateObGroupCheckbox(grpKey);
                saveAllSettings();
                reseedDynSelHardcoded();
                if (activeView === 'OB' && obActiveTab === 'obvrids') { renderOBTabs(); renderOBVridsTable(); }
            });
        });
        // Add buttons
        document.querySelectorAll('.hydra-ob-route-add-btn').forEach(function(btn) {
            btn.addEventListener('click', function() { addObRoute(btn.dataset.grp); });
        });
        document.querySelectorAll('.hydra-ob-route-add-input').forEach(function(inp) {
            inp.addEventListener('keydown', function(e) {
                if (e.key === 'Enter') { addObRoute(inp.id.replace('hydra-ob-ra-', '')); }
            });
        });
    }

    function refreshObRouteItemStates(grpKey) {
        var enabled = obRouteGroupEnabled[grpKey];
        OB_ROUTE_GROUPS[grpKey].routes.forEach(function(rt, idx) {
            var ri = document.getElementById('hydra-ob-ri-' + grpKey + '-' + idx);
            if (!ri) return;
            ri.disabled = !enabled;
            ri.checked  = obIsRouteEnabled(grpKey, rt);
            var lbl = ri.nextElementSibling;
            if (lbl) { enabled ? lbl.classList.remove('disabled') : lbl.classList.add('disabled'); }
        });
        updateObGroupCheckbox(grpKey);
    }

    function updateObGroupCheckbox(grpKey) {
        var cb = document.getElementById('hydra-ob-rg-' + grpKey);
        if (!cb) return;
        var routes  = OB_ROUTE_GROUPS[grpKey].routes;
        var onCount = routes.filter(function(rt) { return obIsRouteEnabled(grpKey, rt); }).length;
        cb.checked       = obRouteGroupEnabled[grpKey];
        cb.indeterminate = obRouteGroupEnabled[grpKey] && onCount > 0 && onCount < routes.length;
    }

    function rebuildObRouteList(grpKey) {
        var container = document.getElementById('hydra-ob-rl-' + grpKey);
        if (!container) return;
        var html = '';
        OB_ROUTE_GROUPS[grpKey].routes.forEach(function(rt, idx) { html += buildObRouteItemHtml(grpKey, rt, idx); });
        container.innerHTML = html;
        bindObRouteEvents();
        updateObGroupCheckbox(grpKey);
    }

    function addObRoute(grpKey) {
        var inp = document.getElementById('hydra-ob-ra-' + grpKey);
        var raw = inp.value.trim().toUpperCase();
        if (!raw) return;
        // Split on spaces, commas, or semicolons to allow multiple entries at once
        var entries = raw.split(/[\s,;]+/).filter(function(s) { return s.length > 0; }).map(function(s) {
            // Strip origin prefix (e.g. ORD9->DII4-CYC1 becomes DII4-CYC1)
            return s.indexOf('->') !== -1 ? s.split('->')[1] : s;
        });
        var added = 0;
        entries.forEach(function(val) {
            if (OB_ROUTE_GROUPS[grpKey].routes.indexOf(val) !== -1) return; // skip duplicates
            OB_ROUTE_GROUPS[grpKey].routes.push(val);
            obRouteItemEnabled[grpKey + '|' + val] = true;
            added++;
        });
        inp.value = '';
        if (added > 0) {
            rebuildObRouteList(grpKey);
            saveAllSettings();
        }
    }

