    // PackageFlix: query Athena via Grafana for per-VRID per-OB-lane size breakdown
    function fetchPackageFlix(nodeId) {
        var sql = "select vrid, ob_lane, size, sum(in_trailer_package_count) as pkg_count from nasc_de_gold.r_pkg_summary where sort_center = '" + nodeId + "' AND concat(sort_center,vrid,ib_lane) like '%" + nodeId + "%' group by vrid, ob_lane, size";
        function buildPayload(queryID) {
            var q = { connectionArgs: { catalog: 'AwsDataCatalog', database: 'nasc_de_gold', region: '__default', resultReuseEnabled: false, resultReuseMaxAgeInMinutes: 60 }, datasource: { type: 'grafana-athena-datasource', uid: 'cdyske3fbtwcgc' }, format: 1, rawSQL: sql, refId: 'A', meta: { queryFlow: 'async' }, intervalMs: 20000, maxDataPoints: 5000, datasourceId: 21 };
            if (queryID) q.queryID = queryID;
            return JSON.stringify({ queries: [q], range: { from: new Date(Date.now() - 6*3600000).toISOString(), to: new Date().toISOString(), raw: { from: 'now-6h', to: 'now' } }, from: String(Date.now() - 6*3600000), to: String(Date.now()) });
        }
        function postQuery(payload) {
            return new Promise(function(resolve, reject) {
                GM_xmlhttpRequest({ method: 'POST', url: 'https://pflixviz.huron.ats.amazon.dev/api/ds/query', headers: { 'Content-Type': 'application/json', 'x-grafana-org-id': '1', 'x-cache-skip': 'true' }, data: payload, withCredentials: true,
                    onload: function(r) { if (r.status !== 200) { reject('PackageFlix HTTP ' + r.status); return; } try { resolve(JSON.parse(r.responseText)); } catch(e) { reject('PackageFlix parse: ' + e); } },
                    onerror: function() { reject('PackageFlix network error'); }, ontimeout: function() { reject('PackageFlix timeout'); }
                });
            });
        }
        function parseRows(resp) {
            var frames = (resp.results && resp.results.A && resp.results.A.frames) || [];
            if (!frames.length || !frames[0].data || !frames[0].data.values || !frames[0].data.values.length) return [];
            var fields = frames[0].schema.fields.map(function(f) { return f.name; });
            var values = frames[0].data.values;
            var rows = [];
            for (var i = 0; i < values[0].length; i++) { var row = {}; for (var j = 0; j < fields.length; j++) row[fields[j]] = values[j][i]; rows.push(row); }
            return rows;
        }
        // Async polling: submit, then poll until finished
        return postQuery(buildPayload(null)).then(function(resp) {
            var frames = (resp.results && resp.results.A && resp.results.A.frames) || [];
            var meta = frames.length && frames[0].schema && frames[0].schema.meta && frames[0].schema.meta.custom;
            if (!meta || !meta.queryID) return parseRows(resp); // sync response
            if (meta.status === 'finished') return parseRows(resp);
            var qid = meta.queryID;
            console.log('[Hydra CM] PackageFlix query started, polling:', qid);
            // Poll up to 20 times (2s interval = 40s max)
            var attempts = 0;
            function poll() {
                attempts++;
                if (attempts > 20) return Promise.reject('PackageFlix poll timeout');
                return new Promise(function(res) { setTimeout(res, 2000); }).then(function() {
                    return postQuery(buildPayload(qid));
                }).then(function(resp2) {
                    var frames2 = (resp2.results && resp2.results.A && resp2.results.A.frames) || [];
                    var meta2 = frames2.length && frames2[0].schema && frames2[0].schema.meta && frames2[0].schema.meta.custom;
                    if (meta2 && meta2.status === 'finished') return parseRows(resp2);
                    if (meta2 && (meta2.status === 'started' || meta2.status === 'running')) return poll();
                    return parseRows(resp2); // try to parse whatever we got
                });
            }
            return poll();
        });
    }

    function gmFetch(url, method, body) {
        method = method || 'GET';
        var _trId = hydraTraceStart('gmFetch ' + method + ' ' + url.slice(0, 100));
        var _timedOut = false;
        return new Promise(function(resolve, reject) {
            // Vista rejects GETs when CSRF token is sent in BOTH URL param and header
            // (URL-encoded vs raw mismatch). For GETs token is in URL; skip the header.
            // For POSTs keep the header because the token is in the body (URL-encoded).
            var _headers = body
                ? { 'anti-csrftoken-a2z': csrfToken, 'Content-Type': 'application/x-www-form-urlencoded' }
                : {};
            GM_xmlhttpRequest({
                method: method, url: url,
                headers: _headers,
                data: body || null, withCredentials: true,
                onload: function(r) {
                    if (_timedOut) return;
                    if (r.status !== 200) {
                        var safeBody = (r && r.responseText && typeof r.responseText === 'string') ? r.responseText.slice(0, 500) : '(no response body)';
                        hydraTraceFail(_trId, 'HTTP ' + r.status);
                        console.error('[Hydra] HTTP ' + r.status + ' on ' + url + '\n' + safeBody);
                        reject('HTTP ' + r.status);
                        return;
                    }
                    hydraTraceEnd(_trId, { status: r.status, bytes: r.responseText ? r.responseText.length : 0 });
                    try { resolve(JSON.parse(r.responseText)); } catch (e) { reject('JSON parse error'); }
                },
                onerror: function(e) { if (!_timedOut) { hydraTraceFail(_trId, 'net-err'); reject(e); } },
            });
            // Hard client-side 60s timeout — the GM_xmlhttpRequest we use has no native timeout set
            setTimeout(function() {
                if (_hydraTraceActive[_trId]) {
                    _timedOut = true;
                    hydraTraceFail(_trId, 'client-timeout-60s');
                    reject('client-timeout-60s');
                }
            }, 60000);
        });
    }

    // SSP endpoints (hrz/ob) require their OWN anti-csrf token, distinct from the
    // Vista token. Scrape it from the SSP OB page HTML. Cached for 15 minutes.
    function fetchSspToken(force) {
        if (!force && sspToken && (Date.now() - sspTokenFetchedAt) < 900000) {
            return Promise.resolve(sspToken);
        }
        return new Promise(function(resolve, reject) {
            GM_xmlhttpRequest({
                method: 'GET', url: 'https://trans-logistics.amazon.com/ssp/dock/hrz/ob', withCredentials: true,
                onload: function(r) {
                    var html = r.responseText || '';
                    var m = html.match(/name=['"]anti-csrftoken-a2z['"]\s+value=['"]([^'"]*)['"]/);
                    if (!m) m = html.match(/value=['"]([^'"]*)['"]\s+name=['"]anti-csrftoken-a2z['"]/);
                    var tok = m ? m[1] : null;
                    if (!tok || tok.length < 5) {
                        console.error('[Hydra] SSP token not found in /ssp/dock/hrz/ob (len=' + html.length + ')');
                        reject('SSP token not found'); return;
                    }
                    sspToken = tok;
                    sspTokenFetchedAt = Date.now();
                    console.log('[Hydra] sspToken set, length=' + sspToken.length);
                    resolve(sspToken);
                },
                onerror: function() { reject('SSP token fetch error'); },
                ontimeout: function() { reject('SSP token fetch timeout'); }
            });
        });
    }

    // POST to an SSP endpoint using the SSP-specific anti-csrf token in the header.
    function gmFetchSsp(url, body) {
        return fetchSspToken(false).then(function(tok) {
            return new Promise(function(resolve, reject) {
                GM_xmlhttpRequest({
                    method: 'POST', url: url,
                    headers: { 'anti-csrftoken-a2z': tok, 'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8', 'X-Requested-With': 'XMLHttpRequest' },
                    data: body || null, withCredentials: true,
                    onload: function(r) {
                        if (r.status !== 200) {
                            console.error('[Hydra] SSP POST HTTP ' + r.status + ' on ' + url);
                            reject('HTTP ' + r.status); return;
                        }
                        try { resolve(JSON.parse(r.responseText)); }
                        catch (e) { reject('SSP JSON parse error'); }
                    },
                    onerror: function() { reject('SSP POST error'); },
                    ontimeout: function() { reject('SSP POST timeout'); }
                });
            });
        });
    }

    function fetchToken() {
        var _tokTrace = hydraTraceStart('fetchToken');
        var _tokTimedOut = false;
        return new Promise(function(resolve, reject) {
            GM_xmlhttpRequest({
                method: 'GET', url: 'https://trans-logistics.amazon.com/sortcenter/vista', withCredentials: true,
                onload: function(r) {
                    if (_tokTimedOut) return;
                    var bodyLen = r.responseText ? r.responseText.length : 0;
                    var html = r.responseText || '';
                    // Flexible regex: accepts either ' or " quotes, either attribute order.
                    // Pattern A: name first, then value (most common)
                    var m = html.match(/name=['"]anti-csrftoken-a2z['"]\s+value=['"]([^'"]*)['"]/);
                    // Pattern B: value first, then name (fallback for reordered HTML)
                    if (!m) m = html.match(/value=['"]([^'"]*)['"]\s+name=['"]anti-csrftoken-a2z['"]/);
                    var tokenFound = m ? m[1] : null;
                    if (!tokenFound) {
                        hydraTraceFail(_tokTrace, { reason: 'token-not-in-html', status: r.status, bodyLen: bodyLen, snippet: html.slice(0, 200) });
                        console.error('[Hydra] CSRF token regex did not match SSP HTML. Page length=' + bodyLen);
                        reject('Token not found'); return;
                    }
                    if (tokenFound.length < 5) {
                        // Empty/trivial token means SSP is in a degraded state. Reject rather
                        // than silently setting csrfToken='' which causes later POSTs to hang.
                        hydraTraceFail(_tokTrace, { reason: 'token-too-short', status: r.status, bodyLen: bodyLen, tokenLen: tokenFound.length });
                        console.error('[Hydra] SSP returned empty CSRF token. Try reloading the page or running mwinit.');
                        reject('Token empty (SSP degraded)'); return;
                    }
                    csrfToken = tokenFound;
                    tokenFetchedAt = Date.now();
                    hydraTraceEnd(_tokTrace, { status: r.status, bodyLen: bodyLen, tokenLen: csrfToken.length, tokenPreview: csrfToken.slice(0, 12) });
                    console.log('[Hydra] csrfToken set, length=' + csrfToken.length);
                    console.log('[Hydra DIAG 1] RAW TOKEN from vista HTML:', JSON.stringify(csrfToken));
                    window.__hydraCsrfToken = csrfToken;  // expose for DevTools
                    resolve(csrfToken);
                },
                onerror: function(e) { if (!_tokTimedOut) { hydraTraceFail(_tokTrace, 'net-err'); reject(e); } },
            });
            // Hard 60s client-side timeout
            setTimeout(function() {
                if (_hydraTraceActive[_tokTrace]) {
                    _tokTimedOut = true;
                    hydraTraceFail(_tokTrace, 'client-timeout-60s');
                    reject('client-timeout-60s');
                }
            }, 60000);
        });
    }

