                var popup = document.getElementById('hydra-ws-popup');
                var h = '<div style="color:var(--h-ob-accent, #20d4f0);font-weight:700;margin-bottom:8px">' + label + ' \u2014 ' + route + ' (' + ctns.length + ' containers)</div>';
                h += '<table style="border-collapse:collapse;width:100%">';
                h += '<tr style="color:var(--h-muted2, #7a8a9a);font-size:10px;border-bottom:1px solid var(--h-border, #2a3a4c)">';
                h += '<td style="padding:2px 8px 4px 0">Container ID</td>';
                h += '<td style="padding:2px 8px 4px">Location</td>';
