        var capSlider = document.getElementById('hydra-autofit-cap-slider');
        var capValue = document.getElementById('hydra-autofit-cap-value');
        if (capSlider) { capSlider.value = Math.round(autoFitCap * 100); if (capValue) capValue.textContent = Math.round(autoFitCap * 100) + '%'; }
        if (capSlider) capSlider.addEventListener('input', function() { autoFitCap = parseInt(capSlider.value, 10) / 100; if (capValue) capValue.textContent = capSlider.value + '%'; applyZoom(); });
        // Update timezone
        var tzInput = document.getElementById('hydra-tz-input');
