        // CPT multi-select dropdown
        (function() {
            var btn = document.getElementById('hydra-cpt-preset');
            var dropdown = document.getElementById('hydra-cpt-dropdown');
            if (!btn || !dropdown) return;

            function buildDropdownItems() {
                var html = '<label style="display:flex;align-items:center;gap:6px;padding:4px 10px;cursor:pointer;color:var(--h-text, #e8eaf0);font-size:12px"><input type="checkbox" value="any" style="accent-color:#ff9900"' + (selectedCptIds.length === 0 ? ' checked' : '') + '> \u2014 Any \u2014</label>';
                cptWindows.forEach(function(w) {
                    var checked = selectedCptIds.indexOf(w.id) !== -1 ? ' checked' : '';
                    var timeStr = ('0' + w.startH).slice(-2) + ':' + ('0' + (w.startM || 0)).slice(-2) + '-' + ('0' + w.endH).slice(-2) + ':' + ('0' + (w.endM || 0)).slice(-2);
                    html += '<label style="display:flex;align-items:center;gap:6px;padding:4px 10px;cursor:pointer;color:var(--h-text, #e8eaf0);font-size:12px"><input type="checkbox" value="' + w.id + '" style="accent-color:#ff9900"' + checked + '> ' + w.label + ' ' + timeStr + '</label>';
                });
                dropdown.innerHTML = html;
            }

            function updateButtonLabel() {
                if (selectedCptIds.length === 0) {
                    btn.textContent = '\u2014 Any \u2014';
                } else if (selectedCptIds.length === 1) {
                    var w = cptWindows.find(function(w) { return w.id === selectedCptIds[0]; });
                    btn.textContent = w ? w.label : selectedCptIds[0];
                } else {
                    btn.textContent = selectedCptIds.length + ' CPT\'s';
                }
            }

            function applyMultiCpt() {
                if (selectedCptIds.length === 0) {
                    // Any - clear start/end
                    var startEl = document.getElementById('hydra-cpt-start-input');
                    var endEl = document.getElementById('hydra-cpt-end-input');
                    if (startEl) startEl.value = '';
                    if (endEl) endEl.value = '';
                } else {
                    // Combine: use earliest start and latest end across all selected
                    var earliestStart = null, latestEnd = null;
                    selectedCptIds.forEach(function(id) {
                        var d = getCptPresetDates(id);
                        var sMs = parseCptMs(d.start);
                        var eMs = parseCptMs(d.end);
                        if (sMs !== null && (earliestStart === null || sMs < earliestStart)) earliestStart = sMs;
                        if (eMs !== null && (latestEnd === null || eMs > latestEnd)) latestEnd = eMs;
                    });
                    var startEl = document.getElementById('hydra-cpt-start-input');
                    var endEl = document.getElementById('hydra-cpt-end-input');
                    var tzOff = getEffectiveTzOffset();
                    function toStr(ms) {
                        var dd = new Date(ms + tzOff * 3600000);
                        return ('0'+(dd.getUTCMonth()+1)).slice(-2)+'/'+('0'+dd.getUTCDate()).slice(-2)+'/'+dd.getUTCFullYear()+' '+('0'+dd.getUTCHours()).slice(-2)+':'+('0'+dd.getUTCMinutes()).slice(-2);
                    }
                    if (startEl && earliestStart !== null) startEl.value = toStr(earliestStart);
                    if (endEl && latestEnd !== null) endEl.value = toStr(latestEnd);
                }
                updateButtonLabel();
                saveAllSettings();
                reseedDynSelHardcoded();
                if (typeof puActive !== 'undefined' && puActive) { renderAllPanes(); }
                else if (activeView === 'OB') { renderOBTabs(); renderOBTable(); }
                else if (activeView === 'PS') { renderPSTable(); }
                else { renderIBTabs(); renderIBTable(); }
            }

            // Toggle dropdown on button click
            btn.addEventListener('click', function(e) {
                e.stopPropagation();
                var isOpen = dropdown.style.display !== 'none';
                dropdown.style.display = isOpen ? 'none' : 'block';
                if (!isOpen) buildDropdownItems();
            });

            // Handle checkbox changes (delegated)
            dropdown.addEventListener('change', function(e) {
                var cb = e.target;
                if (!cb || cb.type !== 'checkbox') return;
                if (cb.value === 'any') {
                    // "Any" always clears all selections (no CPT filter)
                    selectedCptIds = [];
                    cb.checked = true;
                    dropdown.querySelectorAll('input[type="checkbox"]').forEach(function(box) {
                        if (box.value !== 'any') box.checked = false;
                    });
                } else {
                    if (cb.checked) {
                        if (selectedCptIds.indexOf(cb.value) === -1) selectedCptIds.push(cb.value);
                    } else {
                        selectedCptIds = selectedCptIds.filter(function(id) { return id !== cb.value; });
                    }
                }
                // Sync "Any" checkbox: checked when no individual CPTs selected
                var anyBox = dropdown.querySelector('input[value="any"]');
                if (anyBox) anyBox.checked = (selectedCptIds.length === 0);
                // If all were unchecked, ensure "Any" state
                if (selectedCptIds.length === 0 && anyBox) anyBox.checked = true;
                applyMultiCpt();
            });

            // Close dropdown on outside click
            document.addEventListener('click', function() { dropdown.style.display = 'none'; });
            dropdown.addEventListener('click', function(e) { e.stopPropagation(); });

            // Initialize
            updateButtonLabel();
        })();

