        // Reset All Settings (safe + complete): snapshots state, sweeps all
        // hydra_* localStorage keys, stops timers, reloads.
        document.getElementById('hydra-reset-all-btn').addEventListener('click', function() {
            var msg = 'Reset ALL Hydra settings to defaults?\n\n' +
                      'This will permanently remove:\n' +
                      '  \u2022 All saved presets (site configs)\n' +
                      '  \u2022 Column show/hide + order customizations\n' +
                      '  \u2022 Dock door list + size\n' +
                      '  \u2022 CPT windows / WS buffer / diverted lanes\n' +
                      '  \u2022 Panel size, zoom, timezone override\n' +
                      '  \u2022 All other Hydra-specific state\n\n' +
                      'A one-time backup snapshot is saved that you can restore\n' +
                      'by running window.hydraRestoreLastReset() in the console.\n\n' +
                      'Proceed?';
            if (!confirm(msg)) return;
            var btn = this;
            if (btn.disabled) return;
            btn.disabled = true;
            btn.textContent = 'Resetting...';
            try {
                // Stop auto-refresh timer so a pending save can't race the wipe.
                if (typeof stopAutoRefresh === 'function') {
                    try { stopAutoRefresh(); } catch(e) {}
                }
                // Mark loading guard so any in-flight doRefresh short-circuits.
                if (typeof isLoading !== 'undefined') { isLoading = true; }
                // 1. Snapshot EVERY hydra_* key so user can undo.
                var snap = hydraSnapshotAllForReset();
                if (snap) {
                    console.log('[Hydra] Backup created. To restore: run window.hydraRestoreLastReset() before reloading.');
                } else {
                    console.warn('[Hydra] Backup snapshot failed -- reset will proceed without an undo.');
                }
                // 2. Sweep all matching keys (catches ones not in STORAGE_KEYS too).
                var removed = hydraSweepAllKeys();
                console.log('[Hydra] Reset cleared ' + removed.length + ' localStorage keys:', removed);
                // 3. Reload baked presets and show setup wizard
                loadPresetsFromStorage();
                btn.textContent = '\u2714 Reset \u2014 choose preset...';
                // Close settings overlay so wizard is unobstructed
                var _so = document.getElementById('hydra-settings-overlay');
                if (_so) _so.classList.remove('open');
                showSetupWizard(function() {
                    // Preset chosen & saved; apply in-place without reload
                    isLoading = false;
                    if (hydraPresets[activePresetId] && hydraPresets[activePresetId].settings) {
                        applyPresetSettings(hydraPresets[activePresetId].settings);
                    }
                    selectedCptIds = [];
                    updateAutoFitButtons();
                    saveAllSettings();
                    btn.disabled = false;
                    btn.textContent = '\u26a0 Reset All Settings to Default';
                });
            } catch (e) {
                console.error('[Hydra] Reset failed:', e);
                alert('Reset failed: ' + (e && e.message || e) + '\n\nSee console for details.');
                btn.disabled = false;
                btn.innerHTML = '\u26a0 Reset All Settings to Default';
            }
        });

